#include <vector>
#include <algorithm>
using namespace std;

vector<long long> solve(vector<string> words) {
    int n = words.size();
    if (n == 1) {
        return {0};
    }

    int m = n - 1;
    vector<long long> adj;
    for (int i = 0; i < m; i++) {
        const string& a = words[i];
        const string& b = words[i+1];
        int j = 0;
        while (j < a.size() && j < b.size() && a[j] == b[j]) {
            j++;
        }
        adj.push_back(j);
    }

    vector<long long> left_max(m, 0);
    vector<long long> right_max(m, 0);
    if (m > 0) {
        left_max[0] = adj[0];
        for (int i = 1; i < m; i++) {
            left_max[i] = max(left_max[i-1], adj[i]);
        }
        right_max[m-1] = adj[m-1];
        for (int i = m-2; i >= 0; i--) {
            right_max[i] = max(adj[i], right_max[i+1]);
        }
    }

    vector<long long> ans(n, 0);
    for (int i = 0; i < n; i++) {
        long long max1 = 0;
        long long mid = 0;
        long long max3 = 0;

        if (i >= 2) {
            max1 = left_max[i-2];
        }

        if (i <= n-3) {
            max3 = right_max[i+1];
        }

        if (i >= 1 && i < n-1) {
            const string& a = words[i-1];
            const string& b = words[i+1];
            int j = 0;
            while (j < a.size() && j < b.size() && a[j] == b[j]) {
                j++;
            }
            mid = j;
        }

        ans[i] = max(max1, max(mid, max3));
    }

    return ans;
}
